import { tags } from 'decantr/tags';
import { createSignal } from 'decantr/state';
import { css } from 'decantr/css';
import { Button, Card, Badge, Select, icon } from 'decantr/components';
import { LineChart, BarChart, PieChart } from 'decantr/charts';

code.example:
function EarningsDashboard({ data = {} }) {
  const { div, h2, h3, p, span, table, thead, tbody, tr, th, td } = tags;
  const [dateRange, setDateRange] = createSignal('30d');
  const [chartType, setChartType] = createSignal('line');

  const kpis = data.kpis || [
    { label: 'Total Revenue', value: '$12,450', change: '+18.2%', trend: 'up', icon: 'dollar-sign' },
    { label: 'Monthly Recurring', value: '$3,240', change: '+12.5%', trend: 'up', icon: 'repeat' },
    { label: 'Active Subscribers', value: '428', change: '+24', trend: 'up', icon: 'users' },
    { label: 'Churn Rate', value: '2.1%', change: '-0.3%', trend: 'down', icon: 'trending-down' }
  ];

  const transactions = data.transactions || [
    { id: 1, subscriber: 'Alex Chen', tier: 'Pro', amount: 25, date: '2026-03-27', type: 'subscription' },
    { id: 2, subscriber: 'Maria Garcia', tier: 'VIP', amount: 50, date: '2026-03-26', type: 'subscription' },
    { id: 3, subscriber: 'James Wilson', tier: 'Supporter', amount: 5, date: '2026-03-26', type: 'subscription' }
  ];

  const tierData = data.tierBreakdown || [
    { name: 'Supporter', value: 1200, color: '#F97316' },
    { name: 'Pro', value: 2800, color: '#8B5CF6' },
    { name: 'VIP', value: 1600, color: '#14B8A6' }
  ];

  return div({ class: css('_flex _col _gap6') },
    div({ class: css('_flex _jcsb _aic _flexwrap _gap4') },
      h2({ class: css('_heading3') }, 'Earnings'),
      div({ class: css('_flex _gap2') },
        Select({ value: dateRange(), onchange: (e) => setDateRange(e.target.value), options: [
          { value: '7d', label: 'Last 7 days' },
          { value: '30d', label: 'Last 30 days' },
          { value: '90d', label: 'Last 90 days' },
          { value: '1y', label: 'Last year' }
        ]}),
        Button({ variant: 'outline', size: 'sm' }, icon('download', { size: '16', class: css('_mr1') }), 'Export')
      )
    ),
    div({ class: css('_grid _gc2 _lg:gc4 _gap4') },
      ...kpis.map(kpi =>
        Card({ class: css('studio-card _p4 _flex _col _gap2') },
          div({ class: css('_flex _jcsb _aic') },
            span({ class: css('_textsm _fgmuted') }, kpi.label),
            icon(kpi.icon, { size: '18', class: css('_fgmuted') })
          ),
          p({ class: css('_heading2') }, kpi.value),
          Badge({ variant: kpi.trend === 'up' ? 'default' : 'secondary', size: 'sm' },
            icon(kpi.trend === 'up' ? 'trending-up' : 'trending-down', { size: '12', class: css('_mr1') }),
            kpi.change
          )
        )
      )
    ),
    div({ class: css('_grid _gc1 _lg:gc3 _gap6') },
      Card({ class: css('studio-card _p4 _lg:gc2') },
        div({ class: css('_flex _jcsb _aic _mb4') },
          h3({ class: css('_heading5') }, 'Revenue Over Time'),
          div({ class: css('_flex _gap1 _bgmuted/10 _r2 _p1') },
            Button({ variant: chartType() === 'line' ? 'primary' : 'ghost', size: 'sm', onclick: () => setChartType('line') }, icon('activity', { size: '14' })),
            Button({ variant: chartType() === 'bar' ? 'primary' : 'ghost', size: 'sm', onclick: () => setChartType('bar') }, icon('bar-chart-2', { size: '14' }))
          )
        ),
        div({ class: css('_h[300px]') },
          chartType() === 'line'
            ? LineChart({ data: data.revenueTimeline || [], xKey: 'date', yKey: 'revenue', color: '#F97316' })
            : BarChart({ data: data.revenueTimeline || [], xKey: 'date', yKey: 'revenue', color: '#F97316' })
        )
      ),
      Card({ class: css('studio-card _p4') },
        h3({ class: css('_heading5 _mb4') }, 'Revenue by Tier'),
        div({ class: css('_h[200px]') },
          PieChart({ data: tierData, valueKey: 'value', labelKey: 'name' })
        ),
        div({ class: css('_flex _col _gap2 _mt4') },
          ...tierData.map(tier =>
            div({ class: css('_flex _aic _gap2') },
              div({ class: css('_w3 _h3 _r1'), style: `background:${tier.color}` }),
              span({ class: css('_textsm _flex1') }, tier.name),
              span({ class: css('_textsm _fontmedium') }, '$', tier.value.toLocaleString())
            )
          )
        )
      )
    ),
    div({ class: css('_grid _gc1 _lg:gc3 _gap6') },
      Card({ class: css('studio-card _p4 _lg:gc2') },
        div({ class: css('_flex _jcsb _aic _mb4') },
          h3({ class: css('_heading5') }, 'Recent Transactions'),
          Button({ variant: 'ghost', size: 'sm' }, 'View All', icon('arrow-right', { size: '14', class: css('_ml1') }))
        ),
        table({ class: css('_wfull') },
          thead({},
            tr({ class: css('_borderB') },
              th({ class: css('_textsm _fontmedium _fgmuted _pb3 _tl') }, 'Subscriber'),
              th({ class: css('_textsm _fontmedium _fgmuted _pb3 _tl') }, 'Tier'),
              th({ class: css('_textsm _fontmedium _fgmuted _pb3 _tr') }, 'Amount'),
              th({ class: css('_textsm _fontmedium _fgmuted _pb3 _tr') }, 'Date')
            )
          ),
          tbody({},
            ...transactions.map(tx =>
              tr({ class: css('_borderB _last:borderB0') },
                td({ class: css('_py3') }, tx.subscriber),
                td({ class: css('_py3') }, Badge({ variant: 'secondary', size: 'sm' }, tx.tier)),
                td({ class: css('_py3 _tr _fontmedium') }, '+$', tx.amount),
                td({ class: css('_py3 _tr _fgmuted _textsm') }, tx.date)
              )
            )
          )
        )
      ),
      Card({ class: css('studio-card _p4 _flex _col _jcsb') },
        div({},
          h3({ class: css('_heading5 _mb2') }, 'Next Payout'),
          p({ class: css('_heading1 _fgPrimary _mb2') }, '$2,847.50'),
          p({ class: css('_textsm _fgmuted') }, 'Scheduled for April 1, 2026')
        ),
        div({ class: css('_flex _col _gap2 _mt4 _pt4 _borderT') },
          div({ class: css('_flex _jcsb _textsm') },
            span({ class: css('_fgmuted') }, 'Platform fee (5%)'),
            span({}, '-$149.87')
          ),
          div({ class: css('_flex _jcsb _textsm') },
            span({ class: css('_fgmuted') }, 'Processing fee'),
            span({}, '-$2.63')
          ),
          div({ class: css('_flex _jcsb _fontmedium _mt2 _pt2 _borderT') },
            span({}, 'You receive'),
            span({ class: css('_fgSuccess') }, '$2,695.00')
          )
        )
      )
    )
  );
}

