function EarningsSummary({ kpis }) {
  const { div, span, p } = tags;

  return div({ class: css('_grid _gc2 _lg:gc4 _gap4') },
    ...kpis.map(kpi =>
      Card({ class: css('studio-card _p4 _flex _col _gap2') },
        div({ class: css('_flex _jcsb _aic') },
          span({ class: css('_textsm _fgmuted') }, kpi.label),
          icon(kpi.icon, { size: '16', class: css('_fgmuted') })
        ),
        p({ class: css('_heading3') }, kpi.value),
        Badge({ variant: kpi.trend === 'up' ? 'default' : 'secondary', size: 'xs' }, kpi.change)
      )
    )
  );
}

